#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.amethystPylonLaser)]
    public class AmethystPylonLaser : EntityBehaviourDefinition
    {
        public AmethystPylonLaser(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.PlaySound(VanillaSoundID.lightbeam);
            detectBuffer.Clear();
            laserDetector.DetectEntities(entity, detectBuffer);
            var effectsArray = entity.GetDamageEffects();
            var damageEffects = effectsArray == null ? new DamageEffectList() : new DamageEffectList(effectsArray);
            foreach (var target in detectBuffer)
            {
                target.TakeDamage(entity.GetDamage(), damageEffects, entity);
            }
        }
        public static Detector laserDetector = new CollisionDetector(true);
        public List<Entity> detectBuffer = new List<Entity>();
    }
}
